import java.util.Arrays;

public class KMeansSimple {
 static double dist(double[] a, double[] b) {
 double dx = a[0] - b[0];
 double dy = a[1] - b[1];
 return Math.sqrt(dx * dx + dy * dy);
 }

 public static void main(String[] args) {
 double[][] points = { {1,2}, {1,3}, {2,2}, {8,8}, {9,9}, {8,9} };
 int k = 2;
 double[][] centroids = { {1,2}, {9,9} };
 int[] labels = new int[points.length];

 for (int iter = 0; iter < 5; iter++) {
 // Assign step
 for (int i = 0; i < points.length; i++) {
 double bestDist = Double.MAX_VALUE;
 int best = 0;
 for (int c = 0; c < k; c++) {
 double d = dist(points[i], centroids[c]);
 if (d < bestDist) {
 bestDist = d;
 best = c;
 }
 }
 labels[i] = best;
 }

 // Update step
 double[][] newCentroids = new double[k][2];
 int[] counts = new int[k];
 for (int i = 0; i < points.length; i++) {
 int c = labels[i];
 newCentroids[c][0] += points[i][0];
 newCentroids[c][1] += points[i][1];
 counts[c]++;
 }
 for (int c = 0; c < k; c++) {
 newCentroids[c][0] /= counts[c];
 newCentroids[c][1] /= counts[c];
 }
 centroids = newCentroids;
 }

 System.out.println("Labels: " + Arrays.toString(labels));
 System.out.println("Centroids: " + Arrays.deepToString(centroids));
 }
}

#include <stdio.h>
 #include <stdlib.h>
 #include <time.h>

 double reward_prob[] = {0.2, 0.5, 0.8};
 int arms = 3;

 double pull_arm(int arm) {
 double r = (double)rand() / RAND_MAX;
 return r < reward_prob[arm] ? 1.0 : 0.0;
 }

 int main() {
 srand((unsigned)time(NULL));
 double q[3] = {0, 0, 0};
 int counts[3] = {0, 0, 0};
 double epsilon = 0.1;

 for (int t = 0; t < 1000; t++) {
 int action;
 double r = (double)rand() / RAND_MAX;
 if (r < epsilon) {
 action = rand() % arms; // explore
 } else {
 action = 0;
 for (int a = 1; a < arms; a++) {
 if (q[a] > q[action]) action = a; // exploit
 }
 }

 double reward = pull_arm(action);
 counts[action]++;
 q[action] += (reward - q[action]) / counts[action]; // incremental mean
 }

 printf("Estimated values: [%.2f, %.2f, %.2f]
", q[0], q[1], q[2]);
 return 0;
 }
